ee:message.ee:set-payload:
%dw 2.0
output application/json
var installments = vars.installments
var unit = if (sizeOf(vars.unitData) > 0) vars.unitData[0] else null
var totalPrice = unit.Total_Price__c default 0
var paidInstallments = installments filter ($.Status__c == "Paid")
var overdueInstallments = installments filter ($.Status__c == "Overdue")
var upcomingInstallments = installments filter ($.Status__c == "Upcoming" or $.Status__c == "Pending")
var paidAmount = sum(paidInstallments map ($.Amount__c default 0))
var overdueAmount = sum(overdueInstallments map ($.Amount__c default 0))
var nextDue = (upcomingInstallments orderBy $.Due_Date__c)[0].Due_Date__c default null
---
{
    totalPrice: totalPrice,
    paidAmount: paidAmount,
    remainingBalance: totalPrice - paidAmount,
    nextDueDate: nextDue,
    overdueCount: sizeOf(overdueInstallments),
    overdueAmount: overdueAmount,
    totalInstallments: sizeOf(installments),
    paidInstallments: sizeOf(paidInstallments),
    completionPercentage: if (totalPrice > 0) (paidAmount / totalPrice * 100) else 0
}
